import{_ as l,c as o,ag as e,o as a}from"./chunks/framework.mHuDn-wg.js";const b=JSON.parse('{"title":"计算机启动管理","description":"","frontmatter":{},"headers":[],"relativePath":"计算机/计算机软硬件/boot.md","filePath":"计算机/计算机软硬件/boot.md","lastUpdated":null}'),t={name:"计算机/计算机软硬件/boot.md"};function r(n,i,u,d,I,s){return a(),o("div",null,i[0]||(i[0]=[e('<h1 id="计算机启动管理" tabindex="-1">计算机启动管理 <a class="header-anchor" href="#计算机启动管理" aria-label="Permalink to &quot;计算机启动管理&quot;">​</a></h1><p>BIOS（基本输入输出系统）和UEFI（统一可扩展固件接口）是现代计算机中用于启动和管理硬件的两种不同固件标准。BIOS/UEFI根据启动顺序查找可用的启动设备（如硬盘、光驱、USB设备），并加载引导记录.计算机的启动引导记录通常存储在硬盘的第一个扇区（MBR）或EFI系统分区（ESP）中。引导记录其主要任务是：定位引导程序, 加载引导程序, 分区表信息.</p><h2 id="bios" tabindex="-1">BIOS <a class="header-anchor" href="#bios" aria-label="Permalink to &quot;BIOS&quot;">​</a></h2><ul><li>BIOS 是一种传统的固件标准, 最初由IBM在1980年代开发, 用于控制计算机硬件并加载操作系统</li><li>BIOS 同时也是一种嵌入在主板ROM芯片中的程序，用于在计算机启动时初始化硬件设备、加载操作系统，并提供基本的输入输出功能</li><li>运行在32位架构上，<strong>主要通过MBR分区表管理硬盘分区</strong></li><li>BIOS仅支持MBR分区表，<strong>无法直接支持GPT</strong>。如果需要使用GPT，<strong>必须通过UEFI模式启动</strong></li></ul><h2 id="uefi" tabindex="-1">UEFI <a class="header-anchor" href="#uefi" aria-label="Permalink to &quot;UEFI&quot;">​</a></h2><ul><li>UEFI 是Intel开发的一种新型固件标准</li><li>支持64位架构</li><li>UEFI模式能够直接启动操作系统，省去了传统BIOS需要进行的自检过程，从而显著缩短了启动时间</li><li>UEFI默认支持GPT分区表，GPT与UEFI的结合使得启动速度更快，且支持更多的分区和更大的卷</li><li>但某些老旧的操作系统（如Windows XP）可能无法直接识别GPT分区，需要通过CSM（兼容性支持模块）来模拟BIOS环境</li></ul><h2 id="启动模式" tabindex="-1">启动模式 <a class="header-anchor" href="#启动模式" aria-label="Permalink to &quot;启动模式&quot;">​</a></h2><ul><li>BIOS + MBR：<strong>最传统的启动模式</strong>，兼容性最好，适用于大多数老旧操作系统和硬件</li><li>UEFI + GPT：<strong>现代计算机的主流启动模式</strong>，支持大容量硬盘和多分区，适用于最新的操作系统（如Windows 8及以上版本）</li><li>BIOS + GPT：通过CSM模式实现，允许在BIOS模式下启动GPT硬盘，但性能和兼容性可能不如直接使用UEFI模式</li><li>一般计算机启动时按&quot;F2键&quot;会打开 BIOS 或者 UEFI</li></ul><h2 id="引导加载程序" tabindex="-1">引导加载程序 <a class="header-anchor" href="#引导加载程序" aria-label="Permalink to &quot;引导加载程序&quot;">​</a></h2><ul><li>引导加载程序（Boot Loader，又称引导加载器、启动加载器或启动引导器）, 是由计算机固件（BIOS 或 UEFI）启动的软件。</li><li>GRUB（GNU GRand Unified Bootloader）是一种广泛使用的引导加载程序（Boot Loader），主要用于在计算机启动时加载操作系统内核并将其控制权传递给操作系统。</li><li>GRUB 由GNU项目开发的开源软件，支持多操作系统启动和管理，是Linux发行版中最常见的引导加载程序之一 <ul><li>软件的配置文件在 /etc/default/grub</li><li>每当修改 /etc/default/grub 或者 /etc/grub.d/ 中的文件之后，都需要再次生成主配置文件。</li><li>主配置文件 /boot/grub/grub.cfg 的生成过程受到 /etc/default/grub 中的选项和 /etc/grub.d/ 下脚本的影响</li><li>生成主配置文件命令: <code>grub-mkconfig -o /boot/grub/grub.cfg</code></li><li>每次安装或者移除一个内核后，你都需要重新运行一次 <code>grub-mkconfig</code> 命令。</li><li><code>grub-install</code>命令是在设备上安装GRUB引导加载程序的工具, 会创建 /boot/grub 目录, 并在 EFI系统分区的挂载点创建 /EFI/grub/grubx64.efi 引导加载程序文件.</li></ul></li><li><code>efibootmgr</code> 是一个用于管理基于 UEFI 系统上的 EFI 引导项的命令行工具。</li></ul><h2 id="efi分区和引导加载程序" tabindex="-1">EFI分区和引导加载程序 <a class="header-anchor" href="#efi分区和引导加载程序" aria-label="Permalink to &quot;EFI分区和引导加载程序&quot;">​</a></h2><ul><li><p><strong>EFI分区是一种特殊的磁盘分区</strong>，用于存储与启动相关的文件，包括引导加载程序（如GRUB、Windows Boot Manager等）、操作系统内核、驱动程序以及其他与启动相关的应用程序。</p></li><li><p>通常格式化为FAT32或FAT64文件系统，遵循UEFI规范</p></li><li><p>EFI分区是UEFI固件加载启动文件的唯一来源。当计算机启动时，UEFI固件会从EFI分区中读取并加载指定的引导加载程序文件（如.efi格式的文件），然后由引导加载程序进一步加载操作系统内核</p></li><li><p>在Linux系统中，EFI分区通常挂载到/boot/efi 或者 /efi 目录下</p></li><li><p>EFI引导加载程序是存储在EFI分区中的可执行文件（通常以.efi为扩展名），用于加载操作系统内核或引导其他启动项。</p></li><li><p>EFI引导加载程序必须是可执行的.efi文件，这些文件需要符合UEFI规范，并且可以通过UEFI固件直接访问</p></li><li><p>EFI引导加载程序会读取内核镜像文件（如Linux的vmlinuz或Windows的bootia32.efi），并将其加载到内存中</p></li></ul>',12)]))}const E=l(t,[["render",r]]);export{b as __pageData,E as default};
